import SectionHeader from './SectionHeader';

const certs = [
  { org:'Google', name:'Cybersecurity Professional Certificate', badge:'🔄 In Progress' },
  { org:'NVIDIA × ITI', name:'Gen AI Code Camp — LLM & RAG' },
  { org:'Harvard / ITI', name:'CS50 Computer Science' },
  { org:'Sprints × Microsoft', name:'Cybersecurity Training' },
  { org:'IBM / Coursera', name:'Intro to Artificial Intelligence' },
  { org:'Meta / Coursera', name:'Intro to Data Analytics' },
  { org:'Google', name:'Digital Marketing Fundamentals' },
  { org:'Dubai Future Foundation', name:'AI Prompt Engineering' },
  { org:'HP LIFE', name:'Cybersecurity Awareness' },
  { org:'HP LIFE', name:'Data Science & Analytics' },
  { org:'EYouth', name:'Blockchain Technology' },
  { org:'Edraak', name:'Meta Spark AR' },
];

const achievements = [
  { icon:'🥇', year:'2020 · National Level', title:'Scout Excellence — 1st Place', desc:'1st Place at the National Level in the Scout Excellence Competition — exceptional leadership & teamwork.' },
  { icon:'🏆', year:'2019 · Asyut Directorate', title:'Scout Excellence — 1st Place', desc:'1st Place at the Asyut Directorate of Education Scout Competition — strong initiative and organizational skills.' },
];

export default function Certs() {
  return (
    <>
      <section id="certs" className="py-24 px-[5%] bg-parchment">
        <SectionHeader tag="Credentials" title='<em class="italic text-amber not-italic font-serif-display">Certifications</em>' />
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3">
          {certs.map((c, i) => (
            <div key={i}
              className={`reveal cert-bar ${i%4===1?'delay-1':i%4===2?'delay-2':i%4===3?'delay-3':''} relative bg-cream rounded-xl px-4 py-4 border-[1.5px] ${c.badge ? 'border-amber/30 bg-amber/5' : 'border-transparent'} overflow-hidden transition-all hover:border-amber/20 hover:-translate-y-1 hover:shadow-md cursor-default`}>
              <div className="flex items-start justify-between gap-2">
                <div>
                  <p className="text-[.6rem] font-semibold tracking-wider uppercase text-amber mb-1.5">{c.org}</p>
                  <p className="text-[.86rem] font-semibold text-ink2 leading-snug">{c.name}</p>
                </div>
                {c.badge && (
                  <span className="text-[.6rem] font-semibold bg-amber/15 text-amber2 px-2 py-0.5 rounded-full whitespace-nowrap flex-shrink-0">{c.badge}</span>
                )}
              </div>
            </div>
          ))}
        </div>
      </section>

      <section id="achievements" className="py-24 px-[5%] bg-cream">
        <SectionHeader tag="Recognition" title='<em class="italic text-teal not-italic font-serif-display">Achievements</em>' />
        <div className="grid md:grid-cols-2 gap-4">
          {achievements.map((a, i) => (
            <div key={i}
              className={`reveal ${i===1?'delay-1':''} flex gap-4 items-start bg-parchment rounded-2xl p-6 border-[1.5px] border-transparent shadow-sm transition-all hover:border-amber/22 hover:-translate-y-1 hover:shadow-lg`}>
              <div className="text-3xl bg-amber/8 p-3 rounded-xl flex-shrink-0 leading-none">{a.icon}</div>
              <div>
                <p className="text-[.65rem] font-semibold tracking-wider uppercase text-amber mb-1">{a.year}</p>
                <h3 className="font-serif-display text-lg tracking-tight mb-2">{a.title}</h3>
                <p className="text-[.85rem] text-muted2 leading-[1.7]">{a.desc}</p>
              </div>
            </div>
          ))}
        </div>
      </section>
    </>
  );
}
